/// A test plan whose `.xctestplan` file is generated by Tuist.
///
/// Use this to describe a test plan in Swift instead of checking in a static `.xctestplan` file.
/// Tuist writes the file to `path` during generation, which keeps the list of test targets in
/// sync with the manifest even as features are added or removed.
///
/// Pair with `TestAction.testPlans(_:)` to attach generated plans to a scheme.
public struct TestPlan: Equatable, Codable, Sendable {
    /// Path where the generated `.xctestplan` file will be written.
    public var path: Path

    /// Test targets included in the test plan.
    public var testTargets: [TestableTarget]

    /// Whether this plan is the default plan for the scheme.
    public var isDefault: Bool

    public init(
        path: Path,
        testTargets: [TestableTarget],
        isDefault: Bool = false
    ) {
        self.path = path
        self.testTargets = testTargets
        self.isDefault = isDefault
    }
}
